// Revenue Assurance Validation Engine
const pricingRulesRaw = $input.first().json;
const transactionsRaw = $input.last().json;

// Handle single object vs array
const pricingRules = Array.isArray(pricingRulesRaw) ? pricingRulesRaw : [pricingRulesRaw];
const transactions = Array.isArray(transactionsRaw) ? transactionsRaw : [transactionsRaw];

const results = [];
const discrepancies = [];

// Create pricing lookup map for O(1) access
const pricingMap = new Map();
pricingRules.forEach(rule => {
  const key = `${rule.revenue_line}|${rule.currency}|${rule.account_type || 'N/A'}`;
  pricingMap.set(key, rule);
});

console.log(`Processing ${transactions.length} transactions against ${pricingRules.length} pricing rules`);

// Validate each transaction
transactions.forEach((transaction, index) => {
  const key = `${transaction.revenue_line}|${transaction.currency}|${transaction.account_type || 'N/A'}`;
  const pricing = pricingMap.get(key);

  // No pricing rule found
  if (!pricing) {
    const discrepancy = {
      ...transaction,
      expected_fee: 0,
      actual_fee: parseFloat(transaction.applied_fee) || 0,
      variance: parseFloat(transaction.applied_fee) || 0,
      variance_percentage: 100,
      is_valid: false,
      discrepancy_type: 'NO_PRICING_RULE',
      severity: 'HIGH',
      description: `No pricing rule found for ${transaction.revenue_line} (${transaction.currency})`,
      revenue_impact: parseFloat(transaction.applied_fee) || 0,
      pricing_rule_used: key,
      validation_timestamp: new Date().toISOString()
    };
    results.push(discrepancy);
    discrepancies.push(discrepancy);
    return;
  }

  let expectedFee = 0;
  let isValid = false;
  const actualFee = parseFloat(transaction.applied_fee) || 0;
  const txAmount = parseFloat(transaction.transaction_amount) || 0;

  // Calculate expected fee based on fee type
  switch(transaction.fee_type?.toUpperCase()) {
    case 'FLAT':
      expectedFee = parseFloat(pricing.flat_fee_mean || pricing.flat_fee_median || 0);
      isValid = Math.abs(actualFee - expectedFee) <= Math.max(0.01, expectedFee * 0.05);
      break;

    case 'PERCENTAGE':
      const percentageRate = parseFloat(pricing.percentage_fee_mean || pricing.percentage_fee_median || 0);
      expectedFee = (txAmount * percentageRate) / 100;
      isValid = Math.abs(actualFee - expectedFee) <= Math.max(0.01, expectedFee * 0.05);
      break;

    case 'MINIMUM':
      expectedFee = parseFloat(pricing.minimum_fee_mean || pricing.minimum_fee_median || 0);
      isValid = actualFee >= (expectedFee * 0.95);
      break;

    case 'MAXIMUM':
      expectedFee = parseFloat(pricing.maximum_fee_mean || pricing.maximum_fee_median || 999999);
      isValid = actualFee <= (expectedFee * 1.05);
      break;

    default:
      // Complex fee calculation: min(max, max(min, percentage + flat))
      const minFee = parseFloat(pricing.minimum_fee_mean || 0);
      const maxFee = parseFloat(pricing.maximum_fee_mean || 999999);
      const pctFee = (txAmount * parseFloat(pricing.percentage_fee_mean || 0)) / 100;
      const flatFee = parseFloat(pricing.flat_fee_mean || 0);

      expectedFee = Math.max(minFee, Math.min(maxFee, pctFee + flatFee));
      isValid = Math.abs(actualFee - expectedFee) <= Math.max(0.01, expectedFee * 0.05);
  }

  const variance = actualFee - expectedFee;
  const variancePercentage = expectedFee > 0 ? (variance / expectedFee) * 100 : 0;

  const result = {
    ...transaction,
    expected_fee: parseFloat(expectedFee.toFixed(4)),
    actual_fee: actualFee,
    variance: parseFloat(variance.toFixed(4)),
    variance_percentage: parseFloat(variancePercentage.toFixed(2)),
    is_valid: isValid,
    pricing_rule_used: key,
    validation_timestamp: new Date().toISOString()
  };

  results.push(result);

  // Flag discrepancies
  if (!isValid) {
    const absVariance = Math.abs(variance);
    const severity = absVariance > expectedFee * 0.2 ? 'HIGH' : 
                    absVariance > expectedFee * 0.1 ? 'MEDIUM' : 'LOW';

    discrepancies.push({
      ...result,
      discrepancy_type: 'PRICING_VARIANCE',
      severity: severity,
      description: `Fee variance detected: Expected ${expectedFee.toFixed(2)}, Applied ${actualFee.toFixed(2)} (${variancePercentage.toFixed(1)}% difference)`,
      revenue_impact: variance
    });
  }
});

// Calculate summary statistics
const summary = {
  total_transactions: transactions.length,
  valid_transactions: results.filter(r => r.is_valid).length,
  total_discrepancies: discrepancies.length,
  high_severity_count: discrepancies.filter(d => d.severity === 'HIGH').length,
  medium_severity_count: discrepancies.filter(d => d.severity === 'MEDIUM').length,
  low_severity_count: discrepancies.filter(d => d.severity === 'LOW').length,
  total_revenue_impact: discrepancies.reduce((sum, d) => sum + (d.revenue_impact || 0), 0),
  processing_timestamp: new Date().toISOString(),
  batch_id: $input.first().json.batch_id || `batch_${Date.now()}`
};

console.log(`Validation complete: ${summary.valid_transactions}/${summary.total_transactions} valid, ${summary.total_discrepancies} discrepancies found`);

return [{
  json: {
    results: results,
    discrepancies: discrepancies,
    summary: summary
  }
}];

// Prepare discrepancies for batch insert
const data = $json;
const discrepancies = data.discrepancies || [];

if (discrepancies.length === 0) {
  return [];
}

// Format each discrepancy for SQL insertion
const sqlValues = discrepancies.map(d => {
  // Escape single quotes in strings
  const escapeStr = (str) => String(str || '').replace(/'/g, "''");

  return `(
    '${escapeStr(d.transaction_id)}',
    '${escapeStr(d.revenue_line)}',
    '${escapeStr(d.currency)}',
    ${d.expected_fee || 0},
    ${d.actual_fee || 0},
    ${d.variance || 0},
    ${d.variance_percentage || 0},
    '${escapeStr(d.discrepancy_type)}',
    '${escapeStr(d.severity)}',
    '${escapeStr(d.description)}',
    ${d.revenue_impact || 0},
    'PENDING_REVIEW',
    NOW()
  )`;
}).join(',\n');

return [{
  json: {
    sql_values: sqlValues,
    discrepancy_count: discrepancies.length,
    transaction_ids: discrepancies.map(d => d.transaction_id)
  }
}];

// Prepare transaction IDs for update
const data = $node['Validate Transactions'].json;
const results = data.results || [];
const discrepancies = data.discrepancies || [];

if (results.length === 0) {
  return [];
}

const allTxIds = results.map(r => `'${r.transaction_id}'`).join(',');
const discrepancyTxIds = discrepancies.map(d => `'${d.transaction_id}'`).join(',');

return [{
  json: {
    all_transaction_ids: allTxIds,
    discrepancy_transaction_ids: discrepancyTxIds || "''",
    total_processed: results.length
  }
}];

